let dotNetRef = null;
let timeoutId = null;
let timeoutMs = 0;
let isIdle = false;

const events = ['mousemove', 'keydown', 'click', 'scroll'];

function resetTimer() {
    clearTimeout(timeoutId);

    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync('OnUserActive');
    }

    timeoutId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnUserIdle');
    }, timeoutMs);
}

export function initialize(ref, timeoutSeconds) {
    dotNetRef = ref;
    timeoutMs = timeoutSeconds * 1000;
    isIdle = false;

    for (const event of events) {
        document.addEventListener(event, resetTimer, { passive: true });
    }

    // Start the initial idle countdown
    timeoutId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnUserIdle');
    }, timeoutMs);
}

export function dispose() {
    clearTimeout(timeoutId);
    for (const event of events) {
        document.removeEventListener(event, resetTimer);
    }
    dotNetRef = null;
}

